/**
 * Streams an assistant response over Server-Sent Events. Each event
is `data: {"text": "..."}\n\n` followed by a final `data: [DONE]\n\n`.
Grounds Claude on the latest snapshot for the given engagement.

 * @summary Ask Claude about an engagement (SSE stream)
 */
export const SendChatMessageBody = zod.object({
  engagementId: zod.string(),
  question: zod.string(),
  history: zod
    .array(
      zod.object({
        role: zod.enum(["user", "assistant"]),
        content: zod.string(),
      }),
    )
    .optional(),
  referencedSheetIds: zod.array(zod.string()).optional(),
  referencedAtomIds: zod
    .array(zod.string())
    .optional()
    .describe(
      "Optional list of code atom UUIDs the user has explicitly attached\nto this question. Capped server-side. Atoms are fetched, scoped\nto the engagement's jurisdiction, and injected into the system\nprompt alongside any retrieval-discovered atoms.\n",
    ),
  snapshotFocus: zod
    .boolean()
    .optional()
    .describe(
      'Opt this turn into \"snapshot focus mode\" against the\nengagement\'s \*latest\* snapshot. When true, the server loads\nthe full structured `snapshots.payload` blob for that\nsnapshot and injects it into the system prompt inside a\ndedicated `<snapshot_focus>` block, on top of the always-on\nsnapshot atom summary. Use it for deep questions like\n\"what\'s the area of room 204?\" or \"list every door schedule\nentry\" — the cost stays bounded to the turns that need it.\nEquivalent to embedding a\n`{{atom|snapshot|<latestSnapshotId>|focus}}` inline\nreference in the question text. For comparison questions\nthat need to look at \*older\* snapshots too, see\n`snapshotFocusIds`.\n',
    ),
  snapshotFocusIds: zod
    .array(zod.string())
    .optional()
    .describe(
      'Explicit list of snapshot ids to enter focus mode against\nfor this turn (Task #44). Each id must belong to the same\nengagement; foreign ids cause a 400. The server emits one\n`<snapshot_focus snapshot_id=\"…\">` block per id so the\nmodel can answer comparison-style questions that need to\nmine more than just the latest snapshot\'s payload (e.g.\n\"how did the room schedule change between yesterday\'s push\nand today\'s?\"). May be combined with `snapshotFocus: true`\n(the latest id is added if not already present). Capped\nserver-side; ids are de-duplicated.\n',
    ),
});

/**
 * Returns whatever `req.session` the server has attached for the
caller. Today this is derived from the dev `pr_session` cookie
/ `x-requestor` / `x-permissions` header overrides outside
production, and is locked to the anonymous applicant default
in production. Frontends use this to gate admin-only UI (e.g.
the "Users & Roles" sidebar entry only renders when
`permissions` contains `users:manage`).

 * @summary Get current session
 */
export const GetSessionResponse = zod
  .object({
    audience: zod.enum(["internal", "user", "ai"]),
    requestor: zod
      .object({
        kind: zod.enum(["user", "agent"]),
        id: zod.string(),
      })
      .optional()
      .describe(
        "The actor on whose behalf the request is being made. `kind`\ndistinguishes a human user from a machine agent; `id` is opaque\nto the framework (today: dev cookie ids like `u1`; once real\nauth lands: the verified subject id from the auth provider).\n",
      ),
    permissions: zod.array(zod.string()),
  })
  .describe(
    'The session attached to the current request by\n`middlewares\/session.ts`. Frontends consume this to gate\nadmin-only UI — e.g. the \"Users & Roles\" sidebar entry only\nrenders for sessions whose `permissions` include\n`users:manage`. In production the server returns the\nanonymous-applicant default until a real auth layer lands.\n',
  );

