/**
 * Inserts a new row into the `users` profile table. Fails with 409
if a row with the same `id` already exists — use PATCH to edit
an existing profile instead. Requires the `users:manage`
permission claim on the caller's session; anything else is
rejected with 403.

When `avatarUrl` references one of our `/objects/<id>` paths,
the server inspects the actual stored object before the row is
inserted: oversized blobs (above the
`RequestUploadUrlBody.size` cap) get a 413, and a path that
looks like ours but isn't actually present in the bucket gets
a 400. External avatar URLs (pasted by the admin) skip the
check.

 * @summary Create a user profile
 */

export const CreateUserBody = zod.object({
  id: zod
    .string()
    .min(1)
    .describe(
      "Opaque profile id. Must match whatever the session layer\nwill surface for this user — for the dev cookie path that\nmeans values like `u1` \/ `u_abc123`; once real auth lands\nit should be the auth subject id.\n",
    ),
  displayName: zod.string().min(1),
  email: zod.string().nullish(),
  avatarUrl: zod.string().nullish(),
});

